class Solution {
public:
    int countNumbers(string l, string r, int b) {
        long long left = stoll(l, nullptr, b);
        long long right = stoll(r, nullptr, b);
        int len = r.length();
        vector<vector<long long>> dp(len + 1, vector<long long>(b, 0));
        for (int i = 0; i < b; ++i) dp[1][i] = 1;
        for (int i = 2; i <= len; ++i) {
            for (int j = 0; j < b; ++j) {
                for (int k = 0; k <= j; ++k) {
                    dp[i][j] += dp[i - 1][k];
                }
            }
        }
        long long total = 0;
        for (int i = 0; i < b; ++i) total += dp[len][i];
        auto count = [&](long long x) {
            vector<int> digits;
            while (x) {
                digits.push_back(x % b);
                x /= b;
            }
            reverse(digits.begin(), digits.end());
            long long res = 0;
            int last = 0;
            for (int i = 0; i < digits.size(); ++i) {
                for (int j = last; j < digits[i]; ++j) res += dp[digits.size() - i - 1][j];
                if (digits[i] < last) break;
                last = digits[i];
                if (i == digits.size() - 1) ++res;
            }
            return res;
        };
        long long ans = count(right + 1) - count(left);
        return (ans % (int(1e9) + 7) + int(1e9) + 7) % (int(1e9) + 7);
    }
};
